7821 CmpInst::Predicate llvm::getMinMaxPred(SelectPatternFlavor SPF, bool Ordered) {
7822   if (SPF == SPF_SMIN) return ICmpInst::ICMP_SLT;
7823   if (SPF == SPF_UMIN) return ICmpInst::ICMP_ULT;
7824   if (SPF == SPF_SMAX) return ICmpInst::ICMP_SGT;
7825   if (SPF == SPF_UMAX) return ICmpInst::ICMP_UGT;
7826   if (SPF == SPF_FMINNUM)
7827     return Ordered ? FCmpInst::FCMP_OLT : FCmpInst::FCMP_ULT;
7828   if (SPF == SPF_FMAXNUM)
7829     return Ordered ? FCmpInst::FCMP_OGT : FCmpInst::FCMP_UGT;
7830   llvm_unreachable("unhandled!");
7831 }
