7841 Intrinsic::ID llvm::getInverseMinMaxIntrinsic(Intrinsic::ID MinMaxID) {
7842   switch (MinMaxID) {
7843   case Intrinsic::smax: return Intrinsic::smin;
7844   case Intrinsic::smin: return Intrinsic::smax;
7845   case Intrinsic::umax: return Intrinsic::umin;
7846   case Intrinsic::umin: return Intrinsic::umax;
7847   // Please note that next four intrinsics may produce the same result for
7848   // original and inverted case even if X != Y due to NaN is handled specially.
7849   case Intrinsic::maximum: return Intrinsic::minimum;
7850   case Intrinsic::minimum: return Intrinsic::maximum;
7851   case Intrinsic::maxnum: return Intrinsic::minnum;
7852   case Intrinsic::minnum: return Intrinsic::maxnum;
