7879             CurrentPattern.Flavor == SPF_FMINNUM ||
7880             CurrentPattern.Flavor == SPF_FMAXNUM ||
7881             !I->getType()->isIntOrIntVectorTy())
7882           return false;
7883         if (SelectPattern.Flavor != SPF_UNKNOWN &&
7884             SelectPattern.Flavor != CurrentPattern.Flavor)
7885           return false;
7886         SelectPattern = CurrentPattern;
7887         AllCmpSingleUse &=
7888             match(I, m_Select(m_OneUse(m_Value()), m_Value(), m_Value()));
7889         return true;
7890       })) {
7891     switch (SelectPattern.Flavor) {
7892     case SPF_SMIN:
7893       return {Intrinsic::smin, AllCmpSingleUse};
7894     case SPF_UMIN:
