7907 bool llvm::matchSimpleRecurrence(const PHINode *P, BinaryOperator *&BO,
7908                                  Value *&Start, Value *&Step) {
7909   // Handle the case of a simple two-predecessor recurrence PHI.
7910   // There's a lot more that could theoretically be done here, but
7911   // this is sufficient to catch some interesting cases.
7912   if (P->getNumIncomingValues() != 2)
7913     return false;
7914 
7915   for (unsigned i = 0; i != 2; ++i) {
7916     Value *L = P->getIncomingValue(i);
7917     Value *R = P->getIncomingValue(!i);
7918     Operator *LU = dyn_cast<Operator>(L);
7919     if (!LU)
7920       continue;
7921     unsigned Opcode = LU->getOpcode();
7922 
7923     switch (Opcode) {
7924     default:
7925       continue;
7926     // TODO: Expand list -- xor, div, gep, uaddo, etc..
7927     case Instruction::LShr:
7928     case Instruction::AShr:
7929     case Instruction::Shl:
7930     case Instruction::Add:
7931     case Instruction::Sub:
7932     case Instruction::And:
7933     case Instruction::Or:
7934     case Instruction::Mul:
7935     case Instruction::FMul: {
7936       Value *LL = LU->getOperand(0);
7937       Value *LR = LU->getOperand(1);
7938       // Find a recurrence.
7939       if (LL == P)
7940         L = LR;
7941       else if (LR == P)
7942         L = LL;
7943       else
7944         continue; // Check for recurrence with L and R flipped.
7945 
7946       break; // Match!
7947     }
7948     };
7949 
7950     // We have matched a recurrence of the form:
7951     //   %iv = [R, %entry], [%iv.next, %backedge]
7952     //   %iv.next = binop %iv, L
7953     // OR
7954     //   %iv = [R, %entry], [%iv.next, %backedge]
7955     //   %iv.next = binop L, %iv
7956     BO = cast<BinaryOperator>(LU);
7957     Start = R;
7958     Step = L;
7959     return true;
7960   }
7961   return false;
7962 }
