7973 /// Return true if "icmp Pred LHS RHS" is always true.
7974 static bool isTruePredicate(CmpInst::Predicate Pred, const Value *LHS,
7975                             const Value *RHS, const DataLayout &DL,
7976                             unsigned Depth) {
7977   if (ICmpInst::isTrueWhenEqual(Pred) && LHS == RHS)
7978     return true;
7979 
7980   switch (Pred) {
7981   default:
7982     return false;
7983 
7984   case CmpInst::ICMP_SLE: {
7985     const APInt *C;
7986 
7987     // LHS s<= LHS +_{nsw} C   if C >= 0
7988     if (match(RHS, m_NSWAdd(m_Specific(LHS), m_APInt(C))))
7989       return !C->isNegative();
7990     return false;
7991   }
7992 
7993   case CmpInst::ICMP_ULE: {
7994     const APInt *C;
7995 
7996     // LHS u<= LHS +_{nuw} C   for any C
7997     if (match(RHS, m_NUWAdd(m_Specific(LHS), m_APInt(C))))
7998       return true;
7999 
8000     // RHS >> V u<= RHS for any V
8001     if (match(LHS, m_LShr(m_Specific(RHS), m_Value())))
8002       return true;
8003 
8004     // Match A to (X +_{nuw} CA) and B to (X +_{nuw} CB)
8005     auto MatchNUWAddsToSameValue = [&](const Value *A, const Value *B,
8006                                        const Value *&X,
8007                                        const APInt *&CA, const APInt *&CB) {
