8009           match(B, m_NUWAdd(m_Specific(X), m_APInt(CB))))
8010         return true;
8011 
8012       // If X & C == 0 then (X | C) == X +_{nuw} C
8013       if (match(A, m_Or(m_Value(X), m_APInt(CA))) &&
8014           match(B, m_Or(m_Specific(X), m_APInt(CB)))) {
8015         KnownBits Known(CA->getBitWidth());
8016         computeKnownBits(X, Known, DL, Depth + 1, /*AC*/ nullptr,
8017                          /*CxtI*/ nullptr, /*DT*/ nullptr);
8018         if (CA->isSubsetOf(Known.Zero) && CB->isSubsetOf(Known.Zero))
8019           return true;
8020       }
8021 
8022       return false;
8023     };
8024 
8025     const Value *X;
8026     const APInt *CLHS, *CRHS;
8027     if (MatchNUWAddsToSameValue(LHS, RHS, X, CLHS, CRHS))
8028       return CLHS->ule(*CRHS);
