6829 bool llvm::isGuaranteedToTransferExecutionToSuccessor(const Instruction *I) {
6830   // Note: An atomic operation isn't guaranteed to return in a reasonable amount
6831   // of time because it's possible for another thread to interfere with it for an
6832   // arbitrary length of time, but programs aren't allowed to rely on that.
6833 
6834   // If there is no successor, then execution can't transfer to it.
6835   if (isa<ReturnInst>(I))
6836     return false;
6837   if (isa<UnreachableInst>(I))
6838     return false;
6839 
6840   // Note: Do not add new checks here; instead, change Instruction::mayThrow or
6841   // Instruction::willReturn.
6842   //
6843   // FIXME: Move this check into Instruction::willReturn.
6844   if (isa<CatchPadInst>(I)) {
6845     switch (classifyEHPersonality(I->getFunction()->getPersonalityFn())) {
6846     default:
6847       // A catchpad may invoke exception object constructors and such, which
6848       // in some languages can be arbitrary code, so be conservative by default.
6849       return false;
6850     case EHPersonality::CoreCLR:
6851       // For CoreCLR, it just involves a type test.
6852       return true;
6853     }
6854   }
6855 
6856   // An instruction that returns without throwing must transfer control flow
6857   // to a successor.
