6915   case Instruction::Call:
6916     if (auto *II = dyn_cast<IntrinsicInst>(I)) {
6917       switch (II->getIntrinsicID()) {
6918       // TODO: Add more intrinsics.
6919       case Intrinsic::sadd_with_overflow:
6920       case Intrinsic::ssub_with_overflow:
6921       case Intrinsic::smul_with_overflow:
6922       case Intrinsic::uadd_with_overflow:
6923       case Intrinsic::usub_with_overflow:
6924       case Intrinsic::umul_with_overflow:
6925         // If an input is a vector containing a poison element, the
6926         // two output vectors (calculated results, overflow bits)'
6927         // corresponding lanes are poison.
6928         return true;
6929       case Intrinsic::ctpop:
