6931       }
6932     }
6933     return false;
6934   case Instruction::ICmp:
6935   case Instruction::FCmp:
6936   case Instruction::GetElementPtr:
6937     return true;
6938   default:
6939     if (isa<BinaryOperator>(I) || isa<UnaryOperator>(I) || isa<CastInst>(I))
