6947 void llvm::getGuaranteedWellDefinedOps(
6948     const Instruction *I, SmallVectorImpl<const Value *> &Operands) {
6949   switch (I->getOpcode()) {
6950     case Instruction::Store:
6951       Operands.push_back(cast<StoreInst>(I)->getPointerOperand());
6952       break;
6953 
6954     case Instruction::Load:
6955       Operands.push_back(cast<LoadInst>(I)->getPointerOperand());
6956       break;
6957 
6958     // Since dereferenceable attribute imply noundef, atomic operations
6959     // also implicitly have noundef pointers too
6960     case Instruction::AtomicCmpXchg:
6961       Operands.push_back(cast<AtomicCmpXchgInst>(I)->getPointerOperand());
6962       break;
6963 
6964     case Instruction::AtomicRMW:
6965       Operands.push_back(cast<AtomicRMWInst>(I)->getPointerOperand());
6966       break;
6967 
6968     case Instruction::Call:
6969     case Instruction::Invoke: {
6970       const CallBase *CB = cast<CallBase>(I);
6971       if (CB->isIndirectCall())
6972         Operands.push_back(CB->getCalledOperand());
6973       for (unsigned i = 0; i < CB->arg_size(); ++i) {
6974         if (CB->paramHasAttr(i, Attribute::NoUndef) ||
6975             CB->paramHasAttr(i, Attribute::Dereferenceable) ||
6976             CB->paramHasAttr(i, Attribute::DereferenceableOrNull))
6977           Operands.push_back(CB->getArgOperand(i));
6978       }
6979       break;
6980     }
6981     case Instruction::Ret:
6982       if (I->getFunction()->hasRetAttribute(Attribute::NoUndef))
6983         Operands.push_back(I->getOperand(0));
6984       break;
6985     case Instruction::Switch:
6986       Operands.push_back(cast<SwitchInst>(I)->getCondition());
6987       break;
6988     case Instruction::Br: {
6989       auto *BR = cast<BranchInst>(I);
6990       if (BR->isConditional())
6991         Operands.push_back(BR->getCondition());
6992       break;
6993     }
6994     default:
6995       break;
